function check_initializeAlphaIndices_allowedCaller(address caller) public {
    vm.assume(caller == entropyGenerator.allowedCaller());
    vm.prank(caller);
    // Should not revert when called by allowedCaller
    entropyGenerator.initializeAlphaIndices();
    assert(true); // If we reach here, access control is correct
}
